function setProjectAttributes(root = document, mode = "final") {
  // ---- slug: last segment of pathname ("/archives/buyt" => "buyt")
  const path = (window.location.pathname || "/").replace(/\/+$/, "");
  const slug = (path.split("/").filter(Boolean).pop() || "").trim();

  // 1) Project name: set attribute + visible text
  // (this is safe in both modes)
  if (slug) {
    root.querySelectorAll("[data-project-name]").forEach((el) => {
      el.setAttribute("data-project-name", slug);
      el.textContent = slug;
    });
  }

  // Webflow conditional visibility checks
  const isHiddenByWebflow = (el) => {
    if (!el || !el.isConnected) return true;

    if (el.closest(".w-condition-invisible")) return true;

    const cs = window.getComputedStyle(el);
    if (cs.display === "none") return true;
    if (cs.visibility === "hidden" || cs.visibility === "collapse") return true;

    return false;
  };

  const items = Array.from(root.querySelectorAll("[data-project-content-item]"));

  // -------------------------
  // PLACEHOLDER MODE:
  // Do NOTHING to numbers. Keep whatever is in the HTML (your "0000").
  // -------------------------
  if (mode === "placeholder") return;

  // -------------------------
  // FINAL MODE:
  // Number by VISUAL order (top-to-bottom, left-to-right),
  // not DOM order (which can differ in Webflow).
  // Hidden items get cleared so they show nothing.
  // -------------------------

  const visible = [];
  for (const el of items) {
    if (isHiddenByWebflow(el)) {
      el.setAttribute("data-project-content-item", "");
      el.textContent = "";
    } else {
      visible.push(el);
    }
  }

  // Row tolerance so items on the same row sort by left even if tops differ by a few px
  const sampleRect = visible[0]?.getBoundingClientRect?.();
  const rowEps = sampleRect ? Math.max(8, Math.min(24, sampleRect.height * 0.25)) : 12;

  const ordered = visible
    .map((el) => {
      const r = el.getBoundingClientRect();
      return { el, top: r.top, left: r.left };
    })
    .sort((a, b) => {
      const dy = a.top - b.top;
      if (Math.abs(dy) > rowEps) return dy; // different rows
      return a.left - b.left; // same row
    })
    .map((x) => x.el);

  let i = 1;
  for (const el of ordered) {
    const val = String(i).padStart(4, "0");
    el.setAttribute("data-project-content-item", val);
    el.textContent = val;
    i++;
  }
}

