function setVh() {
  const st = S();
  const h = window.visualViewport?.height ?? window.innerHeight;
  const px = h * 0.01;

  if (st.minVhPx === null) st.minVhPx = px;
  st.minVhPx = Math.min(st.minVhPx, px);

  document.documentElement.style.setProperty("--vh", `${st.minVhPx}px`);
}

function bindVhEventsOnce() {
  if (bindVhEventsOnce._bound) return;
  bindVhEventsOnce._bound = true;

  setVh();

  const vv = window.visualViewport;
  if (vv) {
    vv.addEventListener("resize", setVh);
    vv.addEventListener("scroll", setVh); // iOS bar show/hide can show up here
  }

  window.addEventListener("orientationchange", () => {
    const st = S();
    st.minVhPx = null;
    setTimeout(setVh, 50);
  });

  window.addEventListener("resize", () => {
    const st = S();
    if (window.innerWidth !== st.lastViewportWidth) {
      st.lastViewportWidth = window.innerWidth;
      st.minVhPx = null;
      setVh();
    }
  });
}

function initFooterSwordsFight(options = {}) {
  const {
    svgSel = ".footer_swords-svg",
    leftSel = "#swordL, .footer-sword__l",
    rightSel = "#swordR, .footer-sword__r",
    intensity = 1,
    speed = 1,
    pauseOffscreen = false,
    threshold = 0.1,
  } = options;

  const svg = document.querySelector(svgSel);
  if (!svg || typeof gsap === "undefined") {
    return { svg: null, L: null, R: null, kill() {}, pause() {}, resume() {} };
  }

  const pL = svg.querySelector(leftSel);
  const pR = svg.querySelector(rightSel);
  if (!pL || !pR) {
    return { svg, L: null, R: null, kill() {}, pause() {}, resume() {} };
  }

  const NS = "http://www.w3.org/2000/svg";
  const ensureGroup = (pathEl, key) => {
    let g = svg.querySelector(`g[data-sword="${key}"]`);
    if (g) return g;
    g = document.createElementNS(NS, "g");
    g.setAttribute("data-sword", key);
    pathEl.parentNode.insertBefore(g, pathEl);
    g.appendChild(pathEl);
    return g;
  };

  const L = ensureGroup(pL, "L");
  const R = ensureGroup(pR, "R");

  try {
    svg.style.overflow = "visible";
  } catch (e) {}

  gsap.set([L, R], {
    transformBox: "fill-box",
    force3D: true,
    willChange: "transform",
  });

  gsap.set(L, { transformOrigin: "0% 100%" });
  gsap.set(R, { transformOrigin: "100% 100%" });

  const s = (v) => v * intensity;
  const d = (v) => v / Math.max(0.001, speed);

  gsap.set([L, R], { x: 0, y: 0, rotation: 0 });

  const fight = gsap.timeline({
    repeat: -1,
    defaults: { ease: "power2.inOut" },
  });

  const R_PREP = { x: s(1.05), y: s(0.1), r: s(4.5) };
  const R_LUNGE = { x: s(-1.85), y: s(-0.55), r: s(-8.0) };

  const L_PARRY = { x: s(-0.55), y: s(0.2), r: s(7.0) };
  const BIND = {
    L: { x: s(-0.25), y: s(0.1), r: s(4.0) },
    R: { x: s(-1.15), y: s(-0.3), r: s(-5.2) },
  };

  const L_PREP = { x: s(-1.05), y: s(0.1), r: s(-4.5) };
  const L_LUNGE = { x: s(1.85), y: s(-0.55), r: s(8.0) };

  const R_PARRY = { x: s(0.55), y: s(0.2), r: s(-7.0) };
  const BIND2 = {
    L: { x: s(1.15), y: s(-0.3), r: s(5.2) },
    R: { x: s(0.25), y: s(0.1), r: s(-4.0) },
  };

  fight.to(R, { duration: d(0.4), x: R_PREP.x, y: R_PREP.y, rotation: R_PREP.r, ease: "sine.inOut" }, 0);
  fight.to(L, { duration: d(0.4), x: s(0.15), y: s(-0.05), rotation: s(1.2), ease: "sine.inOut" }, 0);

  fight.to(R, { duration: d(0.34), x: R_LUNGE.x, y: R_LUNGE.y, rotation: R_LUNGE.r, ease: "power3.inOut" }, ">-0.05");
  fight.to(L, { duration: d(0.34), x: L_PARRY.x, y: L_PARRY.y, rotation: L_PARRY.r, ease: "power3.inOut" }, "<");

  fight.to(R, { duration: d(0.26), x: BIND.R.x, y: BIND.R.y, rotation: BIND.R.r, ease: "sine.inOut" }, ">-0.02");
  fight.to(L, { duration: d(0.26), x: BIND.L.x, y: BIND.L.y, rotation: BIND.L.r, ease: "sine.inOut" }, "<");

  fight.to(L, { duration: d(0.38), x: L_PREP.x, y: L_PREP.y, rotation: L_PREP.r, ease: "sine.inOut" }, ">+0.10");
  fight.to(R, { duration: d(0.38), x: s(-0.2), y: s(-0.05), rotation: s(-1.0), ease: "sine.inOut" }, "<");

  fight.to(L, { duration: d(0.34), x: L_LUNGE.x, y: L_LUNGE.y, rotation: L_LUNGE.r, ease: "power3.inOut" }, ">-0.05");
  fight.to(R, { duration: d(0.34), x: R_PARRY.x, y: R_PARRY.y, rotation: R_PARRY.r, ease: "power3.inOut" }, "<");

  fight.to(L, { duration: d(0.26), x: BIND2.L.x, y: BIND2.L.y, rotation: BIND2.L.r, ease: "sine.inOut" }, ">-0.02");
  fight.to(R, { duration: d(0.26), x: BIND2.R.x, y: BIND2.R.y, rotation: BIND2.R.r, ease: "sine.inOut" }, "<");

  fight.to([L, R], { duration: d(0.8), x: 0, y: 0, rotation: 0, ease: "power2.inOut" }, ">+0.10");

  let io = null;
  if (pauseOffscreen && "IntersectionObserver" in window) {
    io = new IntersectionObserver(
      ([entry]) => {
        if (!entry.isIntersecting) fight.pause();
        else fight.resume();
      },
      { threshold }
    );
    io.observe(svg);
  }

  function pause() {
    fight.pause();
  }
  function resume() {
    fight.resume();
  }
  function kill() {
    fight.kill();
    gsap.set([L, R], { clearProps: "transform,willChange" });
    if (io) io.disconnect();
  }

  return { svg, L, R, fight, pause, resume, kill };
}

function initLenis() {
  const st = S();
  const mod = window.KLAASSENS?.modules?.lenis;

  const ctx = {
    isMobileVar: false,
    hasScrollTrigger: st.hasScrollTrigger,
    getLenis: () => st.lenis,
    setLenis: (v) => (st.lenis = v),
    getRafId: () => st.lenisRafId,
    setRafId: (id) => (st.lenisRafId = id),
  };

  if (mod?.initLenis) {
    mod.initLenis(ctx);
    return;
  }

  if (st.lenis || !st.hasLenis) return;

  st.lenis = new Lenis({
    lerp: 0.165,
    wheelMultiplier: 1.25,
  });

  window.lenis = st.lenis;

  if (st.hasScrollTrigger) {
    st.lenis.on("scroll", ScrollTrigger.update);
  }

  gsap.ticker.add((time) => {
    st.lenis.raf(time * 1000);
  });

  gsap.ticker.lagSmoothing(0);
}

function resetPage(container) {
  window.scrollTo(0, 0);
  gsap.set(container, { clearProps: "position,top,left,right,bottom" });

  const st = S();
  if (st.hasLenis) {
    st.lenis?.resize?.();
    st.lenis?.start?.();
  }
}

function initBarbaNavUpdate(data) {
  var tpl = document.createElement("template");
  tpl.innerHTML = data.next.html.trim();
  var nextNodes = tpl.content.querySelectorAll("[data-barba-update]");
  var currentNodes = document.querySelectorAll("nav [data-barba-update]");

  currentNodes.forEach(function (curr, index) {
    var next = nextNodes[index];
    if (!next) return;

    var newStatus = next.getAttribute("aria-current");
    if (newStatus !== null) curr.setAttribute("aria-current", newStatus);
    else curr.removeAttribute("aria-current");

    var newClassList = next.getAttribute("class") || "";
    curr.setAttribute("class", newClassList);
  });
}

function initBunnyPlayerBackground(root = document, opts = {}) {
  const cleanup = !!opts.cleanup;

  const players = root?.querySelectorAll?.("[data-bunny-background-init]") || [];
  players.forEach(function (player) {
    if (!player) return;

    // Cleanup mode (for leaving containers)
    if (cleanup) {
      const st = player._bunnyBgState;
      if (st) {
        try {
          if (st.io) st.io.disconnect();
        } catch (_) {}
        try {
          if (st.hls) st.hls.destroy();
        } catch (_) {}

        const video = st.video;
        if (video) {
          try {
            if (st.onPlay) video.removeEventListener("play", st.onPlay);
            if (st.onPlaying) video.removeEventListener("playing", st.onPlaying);
            if (st.onPause) video.removeEventListener("pause", st.onPause);
            if (st.onWaiting) video.removeEventListener("waiting", st.onWaiting);
            if (st.onCanplay) video.removeEventListener("canplay", st.onCanplay);
            if (st.onEnded) video.removeEventListener("ended", st.onEnded);
          } catch (_) {}

          try {
            video.pause();
          } catch (_) {}
          try {
            video.removeAttribute("src");
            video.load();
          } catch (_) {}
        }

        try {
          if (st.onClick) player.removeEventListener("click", st.onClick);
        } catch (_) {}

        player._bunnyBgState = null;
      }

      try {
        player._bunnyBgInit = false;
      } catch (_) {}

      return;
    }

    // Idempotent init
    if (player._bunnyBgInit) return;
    player._bunnyBgInit = true;

    var src = player.getAttribute("data-player-src");
    if (!src) return;

    var video = player.querySelector("video");
    if (!video) return;

    try {
      video.pause();
    } catch (_) {}
    try {
      video.removeAttribute("src");
      video.load();
    } catch (_) {}

    // Attribute helpers
    function setStatus(s) {
      if (player.getAttribute("data-player-status") !== s) {
        player.setAttribute("data-player-status", s);
      }
    }
    function setActivated(v) {
      player.setAttribute("data-player-activated", v ? "true" : "false");
    }
    if (!player.hasAttribute("data-player-activated")) setActivated(false);

    // Flags
    var lazyMode = player.getAttribute("data-player-lazy"); // "true" | "false" (no meta)
    var isLazyTrue = lazyMode === "true";
    var autoplay = player.getAttribute("data-player-autoplay") === "true";
    var initialMuted = player.getAttribute("data-player-muted") === "true";

    // Used to suppress 'ready' flicker when user just pressed play in lazy modes
    var pendingPlay = false;

    // Autoplay forces muted + loop; IO will drive play/pause
    if (autoplay) {
      video.muted = true;
      video.loop = true;
    } else {
      video.muted = initialMuted;
    }

    video.setAttribute("muted", "");
    video.setAttribute("playsinline", "");
    video.setAttribute("webkit-playsinline", "");
    video.playsInline = true;
    if (typeof video.disableRemotePlayback !== "undefined") video.disableRemotePlayback = true;
    if (autoplay) video.autoplay = false;

    var isSafariNative = !!video.canPlayType("application/vnd.apple.mpegurl");
    var canUseHlsJs = !!(window.Hls && Hls.isSupported()) && !isSafariNative;

    // Attach media only once (for actual playback)
    var isAttached = false;
    var userInteracted = false;
    var lastPauseBy = ""; // 'io' | 'manual' | ''
    function attachMediaOnce() {
      if (isAttached) return;
      isAttached = true;

      if (player._hls) {
        try {
          player._hls.destroy();
        } catch (_) {}
        player._hls = null;
      }

      if (isSafariNative) {
        video.preload = isLazyTrue ? "none" : "auto";
        video.src = src;
        video.addEventListener(
          "loadedmetadata",
          function () {
            readyIfIdle(player, pendingPlay);
          },
          { once: true }
        );
      } else if (canUseHlsJs) {
        var hls = new Hls({ maxBufferLength: 10 });
        hls.attachMedia(video);
        hls.on(Hls.Events.MEDIA_ATTACHED, function () {
          hls.loadSource(src);
        });
        hls.on(Hls.Events.MANIFEST_PARSED, function () {
          readyIfIdle(player, pendingPlay);
        });
        player._hls = hls;
      } else {
        video.src = src;
      }
    }

    // Initialize based on lazy mode
    if (isLazyTrue) {
      video.preload = "none";
    } else {
      attachMediaOnce();
    }

    // Toggle play/pause
    function togglePlay() {
      userInteracted = true;
      if (video.paused || video.ended) {
        if (isLazyTrue && !isAttached) attachMediaOnce();
        pendingPlay = true;
        lastPauseBy = "";
        setStatus("loading");
        safePlay(video);
      } else {
        lastPauseBy = "manual";
        video.pause();
      }
    }

    // Toggle mute
    function toggleMute() {
      video.muted = !video.muted;
      player.setAttribute("data-player-muted", video.muted ? "true" : "false");
    }

    // Controls (delegated)
    function onClick(e) {
      var btn = e.target.closest("[data-player-control]");
      if (!btn || !player.contains(btn)) return;
      var type = btn.getAttribute("data-player-control");
      if (type === "play" || type === "pause" || type === "playpause") togglePlay();
      else if (type === "mute") toggleMute();
    }
    player.addEventListener("click", onClick);

    // Media event wiring
    function onPlay() {
      setActivated(true);
      setStatus("playing");
    }
    function onPlaying() {
      pendingPlay = false;
      setStatus("playing");
    }
    function onPause() {
      pendingPlay = false;
      setStatus("paused");
    }
    function onWaiting() {
      setStatus("loading");
    }
    function onCanplay() {
      readyIfIdle(player, pendingPlay);
    }
    function onEnded() {
      pendingPlay = false;
      setStatus("paused");
      setActivated(false);
    }

    video.addEventListener("play", onPlay);
    video.addEventListener("playing", onPlaying);
    video.addEventListener("pause", onPause);
    video.addEventListener("waiting", onWaiting);
    video.addEventListener("canplay", onCanplay);
    video.addEventListener("ended", onEnded);

    // In-view auto play/pause (only when autoplay is true)
    var io = null;
    if (autoplay) {
      if (player._io) {
        try {
          player._io.disconnect();
        } catch (_) {}
      }
      io = new IntersectionObserver(
        function (entries) {
          entries.forEach(function (entry) {
            var inView = entry.isIntersecting && entry.intersectionRatio > 0;
            if (inView) {
              if (isLazyTrue && !isAttached) attachMediaOnce();
              if (lastPauseBy === "io" || (video.paused && lastPauseBy !== "manual")) {
                setStatus("loading");
                if (video.paused) togglePlay();
                lastPauseBy = "";
              }
            } else {
              if (!video.paused && !video.ended) {
                lastPauseBy = "io";
                video.pause();
              }
            }
          });
        },
        { threshold: 0.1 }
      );
      io.observe(player);
      player._io = io;
    }

    // Store state for cleanup
    player._bunnyBgState = {
      video,
      io,
      hls: player._hls || null,
      onClick,
      onPlay,
      onPlaying,
      onPause,
      onWaiting,
      onCanplay,
      onEnded,
    };
  });

  // Helper: Ready status guard
  function readyIfIdle(player, pendingPlay) {
    if (
      !pendingPlay &&
      player.getAttribute("data-player-activated") !== "true" &&
      player.getAttribute("data-player-status") === "idle"
    ) {
      player.setAttribute("data-player-status", "ready");
    }
  }

  // Helper: safe programmatic play
  function safePlay(video) {
    var p = video.play();
    if (p && typeof p.then === "function") p.catch(function () {});
  }
}

function initHorizontal(root = document) {
  if (typeof gsap === "undefined" || typeof ScrollTrigger === "undefined") return null;

  const mm = gsap.matchMedia();
  const cleanups = [];

  mm.add("(min-width: 769px)", () => {
    const horizontals = gsap.utils.toArray("[data-horizontal]", root);

    horizontals.forEach((horizontal) => {
      const horizontalContent = horizontal.querySelector("[data-horizontal_wrapper]");
      if (!horizontal || !horizontalContent) return;

      // kill old instance if re-initted
      horizontal._horizontalTl?.scrollTrigger?.kill?.();
      horizontal._horizontalTl?.kill?.();

      const tl = gsap.timeline({
        defaults: { ease: "none" },
        scrollTrigger: {
          trigger: horizontal,
          start: "top top",
          end: () => "+=" + (horizontalContent.scrollWidth - window.innerWidth),
          pin: true,
          scrub: 1,
          invalidateOnRefresh: true,
        },
      });

      tl.to(horizontalContent, {
        x: () => -(horizontalContent.scrollWidth - window.innerWidth),
        ease: "none",
      });

      horizontal._horizontalTl = tl;
      cleanups.push(() => {
        horizontal._horizontalTl?.scrollTrigger?.kill?.();
        horizontal._horizontalTl?.kill?.();
        horizontal._horizontalTl = null;
      });
    });

    return () => {
      cleanups.forEach((fn) => {
        try {
          fn();
        } catch (e) {}
      });
    };
  });

  mm.add("(max-width: 768px)", () => {
    root.querySelectorAll("[data-horizontal]").forEach((horizontal) => {
      horizontal._horizontalTl?.scrollTrigger?.kill?.();
      horizontal._horizontalTl?.kill?.();
      horizontal._horizontalTl = null;
    });
  });

  return {
    kill() {
      root.querySelectorAll("[data-horizontal]").forEach((horizontal) => {
        horizontal._horizontalTl?.scrollTrigger?.kill?.();
        horizontal._horizontalTl?.kill?.();
        horizontal._horizontalTl = null;
      });
      mm.revert();
    },
  };
}

function initJumpToHelper() {
  if (initJumpToHelper._bound) return;
  initJumpToHelper._bound = true;

  function getFadeTarget(root = document) {
    return (
      root.querySelector?.(".page-wrapper") ||
      root.querySelector?.(".main-wrapper") ||
      document.querySelector(".page-wrapper") ||
      document.querySelector(".main-wrapper") ||
      document.body
    );
  }

  function tweenDone(tween) {
    return new Promise((resolve) => {
      if (!tween) return resolve();
      tween.eventCallback("onComplete", resolve);
    });
  }

  function fadeOutRoot(root = document) {
    const st = S();
    return gsap.to(getFadeTarget(root), {
      autoAlpha: 0,
      duration: st.reducedMotion ? 0 : 0.18,
      ease: "power2.out",
      overwrite: true,
    });
  }

  function fadeInRoot(root = document) {
    const st = S();
    return gsap.to(getFadeTarget(root), {
      autoAlpha: 1,
      duration: st.reducedMotion ? 0 : 0.24,
      ease: "power2.out",
      overwrite: true,
      clearProps: "opacity,visibility",
    });
  }

  function toUrl(href) {
    try {
      return new URL(href, window.location.href);
    } catch (e) {
      return null;
    }
  }

  function normalizePath(path) {
    const clean = (path || "/").replace(/\/+$/, "");
    return clean || "/";
  }

  function isSamePage(url) {
    if (!url) return false;
    return (
      url.origin === window.location.origin &&
      normalizePath(url.pathname) === normalizePath(window.location.pathname) &&
      url.search === window.location.search
    );
  }

  function isMobileViewport() {
    return window.matchMedia("(max-width: 768px)").matches;
  }

  function getLinkFromEventTarget(target) {
    return target.closest("[data-jump-to]");
  }

  function getSelector(link, url) {
    const attr = (link.getAttribute("data-jump-to") || "").trim();
    return attr || url.hash || "";
  }

  function getTargetEl(selector, root = document) {
    if (!selector) return null;

    try {
      const local = root.querySelector?.(selector);
      if (local) return local;
    } catch (e) {}

    try {
      const global = document.querySelector(selector);
      if (global) return global;
    } catch (e) {}

    if (selector.startsWith("#")) {
      return (
        root.getElementById?.(selector.slice(1)) ||
        document.getElementById(selector.slice(1)) ||
        null
      );
    }

    return null;
  }

  function getJumpY(selector, opts = {}) {
    const {
      root = document,
      viewportAnchor = 0.25,
      extraOffset = 0,
    } = opts;

    const el = getTargetEl(selector, root);
    if (!el) return null;

    const rect = el.getBoundingClientRect();
    const pageTop = rect.top + window.pageYOffset;

    return Math.max(0, pageTop - window.innerHeight * viewportAnchor - extraOffset);
  }

  function instantScroll(y) {
    const st = S();
    if (typeof y !== "number") return false;

    if (st.lenis?.scrollTo) {
      try {
        st.lenis.scrollTo(y, {
          immediate: true,
          force: true,
          lock: true,
        });
        return true;
      } catch (e) {}
    }

    window.scrollTo(0, y);
    return true;
  }

  function replaceHash(selector, urlLike = window.location.href) {
    try {
      const url = new URL(urlLike, window.location.href);
      url.hash = selector.startsWith("#") ? selector.slice(1) : selector;
      history.replaceState(null, "", url.pathname + url.search + url.hash);
    } catch (e) {}
  }

  async function refreshScrollSystems() {
    const st = S();
    await nextFrame();
    st.lenis?.resize?.();
    if (st.hasScrollTrigger) ScrollTrigger.refresh(true);
    await nextFrame();
  }

  async function runSamePageJump(selector) {
    const st = S();
    const y = getJumpY(selector, {
      root: document,
      viewportAnchor: 0.25,
      extraOffset: 0,
    });
    if (y == null) return;

    closeMenuIfOpen();
    playTransitionAudio();
    st.lenis?.stop?.();

    await tweenDone(fadeOutRoot(document));
    instantScroll(y);
    replaceHash(selector);
    await refreshScrollSystems();
    window.KLAASSENS?.parallax?.refresh?.();
    window.KLAASSENS?.modules?.dockHide?.refresh?.();
    st.lenis?.start?.();
    await tweenDone(fadeInRoot(document));
  }

  document.addEventListener(
    "click",
    (e) => {
      const link = getLinkFromEventTarget(e.target);
      if (!link) return;

      if (e.metaKey || e.ctrlKey || e.shiftKey || e.altKey) return;
      if (link.hasAttribute("download")) return;
      if ((link.getAttribute("target") || "").toLowerCase() === "_blank") return;

      const href = (link.getAttribute("href") || "").trim();
      if (!href) return;

      const url = toUrl(href);
      if (!url) return;

      const selector = getSelector(link, url);
      if (!selector) return;

      // MOBILE + SAME PAGE:
      // do NOT hijack. Let native anchor behavior happen.
      if (isSamePage(url) && isMobileViewport()) {
        closeMenuIfOpen();

        requestAnimationFrame(() => {
          S().lenis?.resize?.();
          if (S().hasScrollTrigger) ScrollTrigger.refresh(true);
          window.KLAASSENS?.parallax?.refresh?.();
          window.KLAASSENS?.modules?.dockHide?.refresh?.();
        });

        return;
      }

      e.preventDefault();
      e.stopImmediatePropagation();

      if (isSamePage(url)) {
        runSamePageJump(selector);
        return;
      }

      closeMenuIfOpen();

      const st = S();
      st.jumpTransition = {
        href: url.href,
        path: url.pathname + url.search,
        selector,
      };

      requestAnimationFrame(() => {
        barba.go(url.pathname + url.search);
      });
    },
    true
  );
}

// -----------------------------------------
// BOOT (top-level execution stays clean)
// -----------------------------------------

function boot() {
  S(); // ensure state is created (also registers plugin + sets scrollRestoration)
  setupGsapDefaults();
  bindReducedMotionWatcherOnce();

  // ✅ Dynamic Current Year: run once on initial load (swaps handled per lifecycle)
  setDynamicCurrentYear(document);

  // ✅ audio safety on raw initial DOM as well
  initAudio(document);

  // Menu lock observers are started during lifecycle once()
  // VH helper is global
  bindVhEventsOnce();

  initJumpToHelper();

  // Barba
  initBarba();
}

boot();

